document.addEventListener("DOMContentLoaded",()=>{const e=document.querySelectorAll(".timeline-item");if(!("IntersectionObserver"in window))return void e.forEach(e=>e.classList.add("visible"));const t=new IntersectionObserver((e,t)=>{e.forEach((e,r)=>{e.isIntersecting&&(setTimeout(()=>{e.target.classList.add("visible")},150*r),t.unobserve(e.target))})},{threshold:.3,rootMargin:"0px 0px -50px 0px"});e.forEach(e=>t.observe(e))});